// Quick lookup set for O(1) checking
export const BIBLE_WORDS_SET = new Set(BIBLE_VOCABULARY);

/**
 * Check if a word exists in the Bible vocabulary
 */
export function isKnownWord(word: string): boolean {
  return BIBLE_WORDS_SET.has(word.toLowerCase());
}
